   248→
   249→      // Test final classification selection
   250→      expect(result.finalClassification.primary_category).toBe('financial');
   251→      expect(result.finalClassification.confidence).toBeGreaterThan(0.8);
   252→      expect(result.finalClassification.secondary_categories).toContain('actionable');
   253→    });
   254→
   255→    it('should make AI API call with properly formatted prompts', async () => {
