      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'statements@bank.com' },
          { name: 'Subject', value: 'Your account statement is ready' },
        ],
      },
    };

    // Standard test session
    mockSession = {
      id: 'session-789',
      startedAt: new Date('2023-10-15T09:00:00Z'),
      emailCount: 1,
      successCount: 0,
      errorCount: 0,
      processingMode: 'sequential',
      batchSize: 1,
      performanceMetrics: {
        totalDurationMs: 0,
        avgEmailDurationMs: 0,
        parallelStagesCount: 0,
        databaseBatchOps: 0,
      },
      configVersion: 'v1.0.0',
      configSnapshot: {},
      errors: [],
      warnings: [],
    };

    // Mock candidate categories from rule-based scoring
    mockCandidateCategories = {
      financial: 8.5,
      actionable: 4.2,
      account_security: 2.1,
      marketing_promotions: 0.8,
    };

    // Mock extracted features from T035a
    mockExtractedFeatures = {
      semantic_intent: {
        primary_purpose: 'notification',
        action_required: 'view',
        urgency_level: 'medium',
      },
      category_enhancements: {
        financial: {
          applies: true,
          confidence_boost: 0.3,
          evidence: {
            quoted_phrases: ['account statement', 'review your transactions'],
            keywords: ['statement', 'account', 'transactions'],
            reasoning: 'Email contains specific financial account language',
          },
        },
        actionable: {
          applies: true,
          confidence_boost: 0.2,
          evidence: {
            quoted_phrases: ['please review'],
            keywords: ['review'],
            reasoning: 'Email requests user action to review statement',
          },
        },
        account_security: {
          applies: false,
          confidence_boost: 0,
          evidence: {
            quoted_phrases: [],
            keywords: [],
            reasoning: 'No evidence found',
          },
        },
        commerce_logistics: {
          applies: false,
          confidence_boost: 0,
          evidence: {
            quoted_phrases: [],
            keywords: [],
            reasoning: 'No evidence found',
          },
        },
        marketing_promotions: {
          applies: false,
          confidence_boost: -0.1,
          evidence: {
            quoted_phrases: [],
            keywords: [],
            reasoning: 'No promotional language detected',
          },
        },
      },
    };

    // Standard test configuration
    mockConfig = {
      openai: {
        apiKey: 'test-api-key',
        model: 'gpt-4o-mini',
        temperature: 0.0,
        responseFormat: 'json_schema',
      },
      prompts: {
        systemPrompt: [
          'You are an expert email classifier selecting multi-label top-level categories and best-fit subtypes using rule scores + extracted features.',
        ],
        userPrompt: [
          'Decide final categories.',
          '',
          '```xml',
          '<rule_scores>',
          '{candidateCategories}',
          '</rule_scores>',
          '',
          '<extracted_features>',
          '{extractedFeatures}',
          '</extracted_features>',
          '```',
          '',
          'Email Context:',
          'From: {email.from}',
          'Subject: {email.subject}',
          'Body: {email.body}',
          '',
          'Apply thresholds and multi-label policy to provide final classification decisions.',
        ],
      },
      classificationSchema: {
        name: 'final_classification',
        description: 'Final multi-label email classification',
        schema: {
          type: 'object',
          properties: {
            primary_category: { type: 'string' },
            secondary_categories: {
              type: 'array',
              items: { type: 'string' },
            },
            confidence: { type: 'number', minimum: 0, maximum: 1 },
            reasoning: { type: 'string' },
            category_scores: {
              type: 'object',
              additionalProperties: { type: 'number' },
            },
          },
          required: ['primary_category', 'confidence', 'reasoning'],
          additionalProperties: false,
        },
        strict: true,
      },
      skipConditions: {
        highConfidenceThreshold: 15,
        skipReasons: ['hard_assertion', 'high_confidence_rule_match'],
      },
      retryPolicy: {
        maxRetries: 3,
        backoffMs: 1000,
      },
    };
  });

  describe('Final Classification Logic', () => {
    it('should combine candidate scores with AI feature enhancements correctly', async () => {
      // Mock OpenAI response
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                {
                  message: {
                    content: JSON.stringify({
                      primary_category: 'financial',
                      secondary_categories: ['actionable'],
                      confidence: 0.85,
                      reasoning: 'High financial confidence with actionable elements',
                      category_scores: {
                        financial: 11.05,
                        actionable: 5.04,
                      },
                    }),
                  },
                },
              ],
              usage: { total_tokens: 150 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      // Test that enhanced scores are calculated correctly
      expect(result.enhancedScores.financial).toBeCloseTo(8.5 + 8.5 * 0.3, 2); // Base + boost
      expect(result.enhancedScores.actionable).toBeCloseTo(4.2 + 4.2 * 0.2, 2);
      expect(result.enhancedScores.marketing_promotions).toBeCloseTo(0.8 + 0.8 * -0.1, 2);

      // Test final classification selection
      expect(result.finalClassification.primary_category).toBe('financial');
      expect(result.finalClassification.confidence).toBeGreaterThan(0.8);
      expect(result.finalClassification.secondary_categories).toContain('actionable');
    });

    it('should make AI API call with properly formatted prompts', async () => {
      // Mock OpenAI response
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                {
                  message: {
                    content: JSON.stringify({
                      primary_category: 'financial',
                      secondary_categories: ['actionable'],
                      confidence: 0.85,
                      reasoning: 'High financial confidence with actionable elements',
                      category_scores: {
                        financial: 11.05,
                        actionable: 5.04,
                      },
                    }),
                  },
                },
              ],
              usage: { total_tokens: 150 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      // Verify OpenAI was called with correct parameters
      const openaiInstance = mockOpenAI.OpenAI.mock.results[0].value;
      expect(openaiInstance.chat.completions.create).toHaveBeenCalledWith({
        model: 'gpt-4o-mini',
        temperature: 0.0,
        response_format: {
          type: 'json_schema',
          json_schema: {
            name: 'final_classification',
            description: 'Final multi-label email classification',
            schema: mockConfig.classificationSchema.schema,
            strict: true,
          },
        },
        messages: expect.arrayContaining([
          { role: 'system', content: expect.stringContaining('expert email classifier') },
          { role: 'user', content: expect.stringContaining('"financial": 11.05') },
        ]),
      });

      expect(result.aiInvoked).toBe(true);
    });

    it('should handle multi-label classification correctly', async () => {
      // Mock response with multiple categories
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                {
                  message: {
                    content: JSON.stringify({
                      primary_category: 'financial',
                      secondary_categories: ['actionable', 'account_security'],
                      confidence: 0.78,
                      reasoning: 'Financial statement with actionable review request',
                      category_scores: {
                        financial: 11.05,
                        actionable: 5.04,
                        account_security: 2.1,
                      },
                    }),
                  },
                },
              ],
              usage: { total_tokens: 180 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(result.finalClassification.primary_category).toBe('financial');
      expect(result.finalClassification.secondary_categories).toEqual(['actionable', 'account_security']);
      expect(result.finalClassification.confidence).toBeCloseTo(0.78, 2);
    });
  });

  describe('Skip Handling Logic', () => {
    it('should skip AI classification when high confidence threshold is met', async () => {
      const highConfidenceCategories = {
        financial: 16.5, // Above threshold of 15
        actionable: 3.2,
      };

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        highConfidenceCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(result.skipped).toBe(true);
      expect(result.skipReason).toBe('high_confidence');
      expect(result.aiInvoked).toBe(false);
      expect(result.finalClassification.primary_category).toBe('financial');
      expect(result.finalClassification.confidence).toBeGreaterThan(0.9);
    });

    it('should skip AI classification when hard assertion condition is present', async () => {
      const hardAssertionCategories = {
        financial: 12.0, // Below AI threshold but has hard assertion
        actionable: 2.1,
      };

      // Mock that hard assertion was detected
      const extractedFeaturesWithAssertion = {
        ...mockExtractedFeatures,
        hard_assertion_detected: true,
        hard_assertion_category: 'financial',
      };

      const configWithSkipConditions = {
        ...mockConfig,
        skipConditions: {
          ...mockConfig.skipConditions,
          skipReasons: ['hard_assertion', 'high_confidence_rule_match'],
        },
      };

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        hardAssertionCategories,
        extractedFeaturesWithAssertion,
        configWithSkipConditions
      );

      expect(result.skipped).toBe(true);
      expect(result.skipReason).toBe('hard_assertion');
      expect(result.aiInvoked).toBe(false);
    });

    it('should provide complete skip rationale in explainability trace', async () => {
      const highConfidenceCategories = {
        financial: 18.2,
      };

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        highConfidenceCategories,
        mockExtractedFeatures,
        mockConfig
      );

      // Calculate expected enhanced score: 18.2 + (18.2 * 0.3) = 23.66
      const expectedEnhancedScore = 18.2 + 18.2 * 0.3;

      expect(result.explainabilityTrace.aiRoutingDecision).toEqual({
        routedToAI: false,
        reason: 'high_confidence',
        confidenceScore: expectedEnhancedScore,
        threshold: 15,
        skipConditionsEvaluated: ['hard_assertion', 'high_confidence_threshold'],
        decisionRationale: `Highest category score (${expectedEnhancedScore}) exceeds high confidence threshold (15)`,
      });
    });
  });

  describe('Feature Integration', () => {
    it('should properly interpolate prompts with candidate categories and extracted features', async () => {
      const mockOpenAI = require('openai');
      const mockCreate = jest.fn().mockResolvedValue({
        choices: [
          { message: { content: '{"primary_category": "financial", "confidence": 0.8, "reasoning": "test"}' } },
        ],
        usage: { total_tokens: 100 },
      });

      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: { completions: { create: mockCreate } },
      }));

      await aiClassificationStage(mockEmail, mockSession, mockCandidateCategories, mockExtractedFeatures, mockConfig);

      const calledMessages = mockCreate.mock.calls[0][0].messages;
      const userMessage = calledMessages[1].content;

      // Verify interpolation worked correctly
      expect(userMessage).toContain('"financial": 11.05'); // Enhanced score: 8.5 + (8.5 * 0.3)
      expect(userMessage).toContain('"actionable": 5.04'); // Enhanced score: 4.2 + (4.2 * 0.2)
      expect(userMessage).toContain('"primary_purpose": "notification"');
      expect(userMessage).toContain('From: Test Bank <statements@bank.com>');
      expect(userMessage).toContain('Subject: Your account statement is ready');
    });

    it('should apply feature-based confidence boosts to category scores', async () => {
      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      // Verify enhanced scores include confidence boosts
      expect(result.enhancedScores.financial).toBeGreaterThan(mockCandidateCategories.financial);
      expect(result.enhancedScores.actionable).toBeGreaterThan(mockCandidateCategories.actionable);

      // Verify negative boosts are applied
      expect(result.enhancedScores.marketing_promotions).toBeLessThan(mockCandidateCategories.marketing_promotions);
    });

    it('should handle missing or invalid extracted features gracefully', async () => {
      const invalidFeatures = {
        semantic_intent: null,
        category_enhancements: {},
      } as any;

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        invalidFeatures,
        mockConfig
      );

      // Should fall back to original candidate scores
      expect(result.enhancedScores.financial).toBe(mockCandidateCategories.financial);
      expect(result.enhancedScores.actionable).toBe(mockCandidateCategories.actionable);
      expect(result.validationErrors).toContain('Invalid extracted features format');
    });
  });

  describe('Result Formatting', () => {
    it('should return properly formatted AIClassificationResult', async () => {
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                {
                  message: {
                    content: JSON.stringify({
                      primary_category: 'financial',
                      secondary_categories: ['actionable'],
                      confidence: 0.87,
                      reasoning: 'Strong financial indicators with actionable elements',
                      category_scores: { financial: 11.05, actionable: 5.04 },
                    }),
                  },
                },
              ],
              usage: { total_tokens: 125 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      // Verify all required fields are present and correctly typed
      expect(result).toMatchObject({
        finalClassification: {
          primary_category: expect.any(String),
          secondary_categories: expect.any(Array),
          confidence: expect.any(Number),
          reasoning: expect.any(String),
        },
        enhancedScores: expect.any(Object),
        aiInvoked: expect.any(Boolean),
        skipped: expect.any(Boolean),
        processingDurationMs: expect.any(Number),
        tokenUsage: expect.any(Number),
        apiCallCount: expect.any(Number),
        retryCount: expect.any(Number),
        explainabilityTrace: expect.any(Object),
      });

      expect(result.finalClassification.confidence).toBeGreaterThanOrEqual(0);
      expect(result.finalClassification.confidence).toBeLessThanOrEqual(1);
    });

    it('should include complete explainability trace', async () => {
      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(result.explainabilityTrace).toHaveProperty('candidateScoresInput');
      expect(result.explainabilityTrace).toHaveProperty('extractedFeaturesInput');
      expect(result.explainabilityTrace).toHaveProperty('enhancementCalculations');
      expect(result.explainabilityTrace).toHaveProperty('aiRoutingDecision');
      expect(result.explainabilityTrace).toHaveProperty('finalDecisionRationale');

      // Verify trace includes score enhancement details
      expect(result.explainabilityTrace.enhancementCalculations).toEqual(
        expect.arrayContaining([
          expect.objectContaining({
            category: 'financial',
            originalScore: 8.5,
            confidenceBoost: 0.3,
            enhancedScore: expect.any(Number),
          }),
        ])
      );
    });
  });

  describe('Error Handling and Retry Logic', () => {
    it('should retry on OpenAI API failures with exponential backoff', async () => {
      const mockOpenAI = require('openai');
      const mockCreate = jest
        .fn()
        .mockRejectedValueOnce(new Error('API rate limit'))
        .mockRejectedValueOnce(new Error('Temporary failure'))
        .mockResolvedValueOnce({
          choices: [
            { message: { content: '{"primary_category": "financial", "confidence": 0.8, "reasoning": "test"}' } },
          ],
          usage: { total_tokens: 100 },
        });

      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: { completions: { create: mockCreate } },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(mockCreate).toHaveBeenCalledTimes(3);
      expect(result.retryCount).toBe(2);
      expect(result.apiCallCount).toBe(3);
      expect(result.finalClassification.primary_category).toBe('financial');
    });

    it('should fail gracefully after max retries exhausted', async () => {
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockRejectedValue(new Error('Persistent API failure')),
          },
        },
      }));

      await expect(
        aiClassificationStage(mockEmail, mockSession, mockCandidateCategories, mockExtractedFeatures, mockConfig)
      ).rejects.toThrow('AI classification failed after 3 retries: Persistent API failure');
    });

    it('should handle invalid JSON responses from OpenAI', async () => {
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [{ message: { content: 'Invalid JSON response' } }],
              usage: { total_tokens: 50 },
            }),
          },
        },
      }));

      await expect(
        aiClassificationStage(mockEmail, mockSession, mockCandidateCategories, mockExtractedFeatures, mockConfig)
      ).rejects.toThrow('Invalid JSON response from OpenAI');
    });

    it('should validate input parameters and throw descriptive errors', async () => {
      await expect(
        aiClassificationStage(null as any, mockSession, mockCandidateCategories, mockExtractedFeatures, mockConfig)
      ).rejects.toThrow('Invalid email input');

      await expect(
        aiClassificationStage(mockEmail, mockSession, mockCandidateCategories, mockExtractedFeatures, {
          ...mockConfig,
          openai: { ...mockConfig.openai, apiKey: '' },
        })
      ).rejects.toThrow('Invalid configuration: OpenAI API key is required');
    });
  });

  describe('Performance and Token Usage Tracking', () => {
    it('should track processing duration accurately', async () => {
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockImplementation(
              () =>
                new Promise((resolve) =>
                  setTimeout(
                    () =>
                      resolve({
                        choices: [
                          {
                            message: {
                              content: '{"primary_category": "financial", "confidence": 0.8, "reasoning": "test"}',
                            },
                          },
                        ],
                        usage: { total_tokens: 100 },
                      }),
                    100
                  )
                )
            ),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(result.processingDurationMs).toBeGreaterThan(90); // Account for processing time
      expect(result.tokenUsage).toBe(100);
    });

    it('should track token usage for cost monitoring', async () => {
      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                { message: { content: '{"primary_category": "financial", "confidence": 0.8, "reasoning": "test"}' } },
              ],
              usage: { total_tokens: 250, prompt_tokens: 180, completion_tokens: 70 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        mockConfig
      );

      expect(result.tokenUsage).toBe(250);
      expect(result.explainabilityTrace.apiUsage).toEqual({
        totalTokens: 250,
        promptTokens: 180,
        completionTokens: 70,
      });
    });
  });

  describe('Configuration Integration', () => {
    it('should support backward compatibility with json_object response format', async () => {
      const legacyConfig = {
        ...mockConfig,
        openai: {
          ...mockConfig.openai,
          responseFormat: 'json_object' as const,
        },
      };

      const mockOpenAI = require('openai');
      mockOpenAI.OpenAI.mockImplementation(() => ({
        chat: {
          completions: {
            create: jest.fn().mockResolvedValue({
              choices: [
                { message: { content: '{"primary_category": "financial", "confidence": 0.8, "reasoning": "test"}' } },
              ],
              usage: { total_tokens: 100 },
            }),
          },
        },
      }));

      const result = await aiClassificationStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockExtractedFeatures,
        legacyConfig
      );

      expect(result.finalClassification.primary_category).toBe('financial');

      // Verify correct response_format was used
      const openaiInstance = mockOpenAI.OpenAI.mock.results[0].value;
      expect(openaiInstance.chat.completions.create).toHaveBeenCalledWith(
        expect.objectContaining({
          response_format: { type: 'json_object' },
        })
      );
    });
  });
});

