          evidence: {
            quoted_phrases: [],
            keywords: [],
            reasoning: 'No promotional language detected',
          },
        },
      },
    };

    // Standard test configuration
    mockConfig = {
      openai: {
        apiKey: 'test-api-key',
        model: 'gpt-4o-mini',
        temperature: 0.0,
        responseFormat: 'json_schema',
      },
      prompts: {
